--
-- Table structure for table `audit_logs`
--

DROP TABLE IF EXISTS `audit_logs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `audit_logs` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` int(10) unsigned DEFAULT NULL COMMENT 'User who performed the action',
  `action` varchar(100) NOT NULL COMMENT 'Action performed: create, update, delete, login, logout, etc.',
  `model` varchar(100) DEFAULT NULL COMMENT 'Human-friendly model name (e.g., Ticket)',
  `model_type` varchar(100) DEFAULT NULL COMMENT 'Model class name (e.g., App\\Ticket)',
  `model_id` bigint(20) unsigned DEFAULT NULL COMMENT 'ID of the affected model',
  `old_values` text DEFAULT NULL COMMENT 'JSON of old values before change',
  `new_values` text DEFAULT NULL COMMENT 'JSON of new values after change',
  `ip_address` varchar(45) DEFAULT NULL COMMENT 'IP address of the user',
  `user_agent` text DEFAULT NULL COMMENT 'User agent string',
  `description` text DEFAULT NULL COMMENT 'Human-readable description of the action',
  `event_type` varchar(50) NOT NULL DEFAULT 'model' COMMENT 'Event type: model, auth, system',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_audit_user` (`user_id`),
  KEY `idx_audit_model_type` (`model_type`),
  KEY `idx_audit_model_id` (`model_id`),
  KEY `idx_audit_action` (`action`),
  KEY `idx_audit_model_composite` (`model_type`,`model_id`),
  KEY `idx_audit_created` (`created_at`),
  KEY `idx_audit_event_type` (`event_type`),
  KEY `idx_audit_user_created` (`user_id`,`created_at`),
  CONSTRAINT `audit_logs_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=1981 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

